noncompliant:
#include <format>
#include <locale>

void func() {
    std::locale loc("de_DE.UTF-8");
    double value = 1234.567;
    // Noncompliant: locale passed but L flag not used
    std::string result = std::format(loc, "{}", value);
}

compliant:
#include <format>
#include <locale>

void func() {
    std::locale loc("de_DE.UTF-8");
    double value = 1234.567;
    // Compliant: using L flag with locale
    std::string result = std::format(loc, "{:L}", value);
}
